export const MarketplaceBanner = ({ marketplaceEnabled = true, showBanner = true }) => {
  if (!marketplaceEnabled || !showBanner) {
    return null;
  }

  const handleExploreMarketplace = () => {
    if (marketplaceEnabled) {
      window.open('/integrations/marketplace', '_blank');
    } else {
      toast.error('Please enable marketplace to add plugins');
    }
  };

  return (
    <div className="marketplace-explore-banner" data-cy="marketplace-explore-banner">
      <span className="marketplace-explore-banner__text">
        Can&apos;t find what you&apos;re looking for? Explore the marketplace to add more plugins.
      </span>
      <button
        type="button"
        className="marketplace-explore-banner__button"
        onClick={handleExploreMarketplace}
        data-cy="explore-marketplace-button"
      >
        <StoreIcon />
        Explore Marketplace
      </button>
    </div>
  );
};
